    "app.nim": "import times\nimport frameos/types\n\ntype\n  AppConfig* = object\n    format*: string\n    formatCustom*: string\n\n  App* = ref object of AppRoot\n    appConfig*: AppConfig\n\nproc get*(self: App, context: ExecutionContext): string =\n  result = now().format(case self.appConfig.format:\n    of \"custom\": self.appConfig.formatCustom\n    else: self.appConfig.format)\n",
    "app_loader.nim": "{.warning[UnusedImport]: off.}\nimport json\nimport options\nimport strutils\nimport pixie\nimport frameos/values\nimport frameos/types\nimport ./app as app_module\n\nproc init*(\n    node: DiagramNode,\n    scene: FrameScene,\n): AppRoot =\n  let params = node.data[\"config\"]\n  if params.kind != JObject:\n    raise newException(Exception, \"Invalid config format\")\n  let config = app_module.AppConfig(\n    format: params{\"format\"}.getStr(\"HH:mm:ss\"),\n    formatCustom: params{\"formatCustom\"}.getStr(\"\"),\n  )\n\n  result = app_module.App(\n    appConfig: config,\n    nodeName: node.data{\"name\"}.getStr(),\n    nodeId: node.id,\n    scene: scene,\n    frameConfig: scene.frameConfig,\n  )\n\n\nproc setField*(self: AppRoot, field: string, value: Value) =\n  let app = app_module.App(self)\n  case field:\n  of \"format\":\n    app.appConfig.format = value.asString()\n  of \"formatCustom\":\n    app.appConfig.formatCustom = value.asString()\n  else:\n    raise newException(ValueError, \"Unknown field: \" & field)\n\nproc get*(self: AppRoot, context: ExecutionContext): Value =\n  return app_module.get(app_module.App(self), context)\n",
    "config.json": "{\n  \"name\": \"Clock\",\n  \"description\": \"Return the current time\",\n  \"category\": \"data\",\n  \"version\": \"1.0.0\",\n  \"fields\": [\n    {\n      \"markdown\": \"[Date format syntax](https://nim-lang.org/2.0.2/times.html)\"\n    },\n    {\n      \"name\": \"format\",\n      \"type\": \"select\",\n      \"options\": [\"yyyy-MM-dd\", \"yyyy-MM-dd HH:mm:ss\", \"HH:mm:ss:fff\", \"HH:mm:ss\", \"HH:mm\", \"custom\"],\n      \"value\": \"HH:mm:ss\",\n      \"required\": true,\n      \"label\": \"Format\",\n      \"placeholder\": \"HH:mm:ss\"\n    },\n    {\n      \"name\": \"formatCustom\",\n      \"type\": \"string\",\n      \"value\": \"\",\n      \"required\": false,\n      \"label\": \"Custom format\",\n      \"placeholder\": \"\",\n      \"showIf\": [\n        {\n          \"field\": \"format\",\n          \"operator\": \"eq\",\n          \"value\": \"custom\"\n        }\n      ]\n    }\n  ],\n  \"output\": [\n    {\n      \"name\": \"time\",\n      \"type\": \"string\"\n    }\n  ]\n}\n"
