    "app.nim": "import frameos/apps\nimport frameos/types\nimport frameos/utils/http_client\n\ntype\n  AppConfig* = object\n    url*: string\n\n  App* = ref object of AppRoot\n    appConfig*: AppConfig\n\nproc get*(self: App, context: ExecutionContext): string =\n  let url = self.appConfig.url\n  try:\n    return boundedGetContent(url, maxBytes = self.maxHttpResponseBytes())\n  except CatchableError as e:\n    self.logError e.msg\n    return e.msg\n",
    "app_loader.nim": "{.warning[UnusedImport]: off.}\nimport json\nimport options\nimport strutils\nimport pixie\nimport frameos/values\nimport frameos/types\nimport ./app as app_module\n\nproc init*(\n    node: DiagramNode,\n    scene: FrameScene,\n): AppRoot =\n  let params = node.data[\"config\"]\n  if params.kind != JObject:\n    raise newException(Exception, \"Invalid config format\")\n  let config = app_module.AppConfig(\n    url: params{\"url\"}.getStr(\"\"),\n  )\n\n  result = app_module.App(\n    appConfig: config,\n    nodeName: node.data{\"name\"}.getStr(),\n    nodeId: node.id,\n    scene: scene,\n    frameConfig: scene.frameConfig,\n  )\n\n\nproc setField*(self: AppRoot, field: string, value: Value) =\n  let app = app_module.App(self)\n  case field:\n  of \"url\":\n    app.appConfig.url = value.asString()\n  else:\n    raise newException(ValueError, \"Unknown field: \" & field)\n\nproc get*(self: AppRoot, context: ExecutionContext): Value =\n  return app_module.get(app_module.App(self), context)\n",
